#!/usr/bin/env python3
# Piece 1c-fix (dream-os) — port the two dreamai cures into Kriya:
#   * OPEN BINDER (dreamai 01eb949): binderless attribute atoms attach to the
#     binder Kriya is already working this turn — no more orphan rows / five-binder
#     stutter. kriya_client opens; date/note/money/stage/etc attach; explicit
#     binder_id always wins; persists across a suspended (asked) session.
#   * THE CLOCK (dreamai 364f854): today's date is injected into Kriya's system,
#     so a bare "12 Dec" resolves to the next occurrence, never a guessed past year.
#
# Overwrites kriyaPrimitives.js (surfaces binder_id from writes), kriyaTurn.js
# (the tracker + clock), myraLoop.js (passes today into Kriya). Pure overwrite.

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/kriyaPrimitives.js': '',
    'src/agent/kriyaTurn.js': '',
    'src/agent/myraLoop.js': '',
}
def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    print("\nPiece 1c-fix written. Open-binder + clock cures live in Kriya.")
if __name__=="__main__": main()
